NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
CI MAXN = 110;
int c, d, ans, f[MAXN][MAXN], a[MAXN], b[MAXN], kk;
string s, ss;
int dd(int a, int b)
{
	if (a == b) return 5;
	if ((a == 2 && b == 1) || (b == 2 && a == 1)) return -1;
	if ((a == 3 && b == 1) || (b == 3 && a == 1)) return -2;
	if ((a == 4 && b == 1) || (b == 4 && a == 1)) return -1;
	if ((a == 2 && b == 3) || (b == 2 && a == 3)) return -3;
	if ((a == 2 && b == 4) || (b == 2 && a == 4)) return -2;
	if ((a == 3 && b == 4) || (b == 3 && a == 4)) return -2;
	if ((a == 5 && b == 1) || (b == 5 && a == 1)) return -3;
	if ((a == 5 && b == 2) || (b == 5 && a == 2)) return -4;
	if ((a == 5 && b == 3) || (b == 5 && a == 3)) return -2;
	if ((a == 5 && b == 4) || (b == 5 && a == 4)) return -1;

}
signed main(void)
{
	cin >> c >> s >> d >> ss;
	FOR(i,0,s.size())
	{
		if (s[i] == 'A')
		{
			a[i + 1] = 1;
		}
		if (s[i] == 'C')
		{
			a[i + 1] = 2;
		}
		if (s[i] == 'G')
		{
			a[i + 1] = 3;
		}
		if (s[i] == 'T')
		{
			a[i + 1] = 4;
		}
	}
	FOR(i,0,ss.size())
	{
		if (ss[i] == 'A')
		{
			b[i + 1] = 1;
		}
		if (ss[i] == 'C')
		{
			b[i + 1] = 2;
		}
		if (ss[i] == 'G')
		{
			b[i + 1] = 3;
		}
		if (ss[i] == 'T')
		{
			b[i + 1] = 4;
		}
	}
	f[0][0] = 0;
	FOR(i, 1, s.size())
	{
		f[i][0] = f[i - 1][0] + dd(a[i], 5);
	}
	FOR(i, 1, ss.size())
	{
		f[0][i] = f[0][i - 1] + dd(5, b[i]);
	}

	FOR(i, 1, s.size())
	{
		FOR(j, 1, ss.size())
		{
			f[i][j] = max(f[i - 1][j - 1] + dd(a[i], b[j]), max(f[i - 1][j] + dd(a[i], 5), f[i][j - 1] + dd(5, b[j])));
		}
	}
	cout << f[s.size()][ss.size()];
	return false;
}
